const limit = Math.min((body as any).limit ?? 10, 100);
    const data = await vendorFetch<{ data: any[] }>({
      bearer,
      method: "GET",
      path: "/charges",
      query: { limit, "expand[]": "data.customer" },
    });
    const payments = (data.data ?? []).map((c: any) => ({
      id: c.id,
      amount: c.amount / 100,
      currency: c.currency?.toUpperCase() ?? null,
      status: c.status,
      description: c.description ?? null,
      created: c.created ? new Date(c.created * 1000).toISOString() : null,
      customer_email: c.billing_details?.email ?? null,
      receipt_url: c.receipt_url ?? null,
      paid: c.paid === true,
      refunded: c.refunded === true,
    }));
    return NextResponse.json({ payments, count: payments.length });

const params = new URLSearchParams();
    params.set("line_items[0][price_data][currency]", String((body as any).currency).toLowerCase());
    params.set("line_items[0][price_data][product_data][name]", String((body as any).product_name));
    params.set("line_items[0][price_data][unit_amount]", String(Math.round(Number((body as any).amount) * 100)));
    params.set("line_items[0][quantity]", "1");
    if ((body as any).description) {
      params.set("line_items[0][price_data][product_data][description]", String((body as any).description));
    }
    const res = await fetch("https://api.stripe.com/v1/payment_links", {
      method: "POST",
      headers: {
        authorization: `Bearer ${bearer}`,
        "content-type": "application/x-www-form-urlencoded",
      },
      body: params.toString(),
    });
    const text = await res.text();
    let parsed: any = null;
    try { parsed = JSON.parse(text); } catch {}
    if (!res.ok) throw new VendorApiError(res.status, parsed, `Stripe POST /payment_links → ${res.status}: ${text.slice(0, 240)}`);
    return NextResponse.json({ url: parsed.url, id: parsed.id });

if ((body as any).simulate) {
      return NextResponse.json({
        invoice_id: `simulate:invoice`,
        status: "draft",
        amount: (body as any).amount,
        currency: (body as any).currency,
        customer_email: (body as any).customer_email,
        simulated: true,
      });
    }
    // Find-or-create the customer by email, then create + finalize the invoice.
    const findCust = await fetch(`https://api.stripe.com/v1/customers/search?query=${encodeURIComponent(`email:'${(body as any).customer_email}'`)}`, {
      method: "GET",
      headers: { authorization: `Bearer ${bearer}`, accept: "application/json" },
    });
    const found = await findCust.json() as { data?: any[] };
    let customerId: string;
    if (found.data && found.data.length > 0) {
      customerId = found.data[0].id;
    } else {
      const params = new URLSearchParams({ email: String((body as any).customer_email) });
      const newCust = await fetch("https://api.stripe.com/v1/customers", {
        method: "POST",
        headers: { authorization: `Bearer ${bearer}`, "content-type": "application/x-www-form-urlencoded" },
        body: params.toString(),
      });
      const c = await newCust.json() as { id: string };
      customerId = c.id;
    }
    // Create invoice item, then create the invoice, then finalize+send.
    const itemBody = new URLSearchParams({
      customer: customerId,
      amount: String(Math.round(Number((body as any).amount) * 100)),
      currency: String((body as any).currency).toLowerCase(),
      description: String((body as any).description),
    });
    await fetch("https://api.stripe.com/v1/invoiceitems", {
      method: "POST",
      headers: { authorization: `Bearer ${bearer}`, "content-type": "application/x-www-form-urlencoded" },
      body: itemBody.toString(),
    });
    const invBody = new URLSearchParams({
      customer: customerId,
      collection_method: "send_invoice",
      days_until_due: "7",
    });
    const invRes = await fetch("https://api.stripe.com/v1/invoices", {
      method: "POST",
      headers: { authorization: `Bearer ${bearer}`, "content-type": "application/x-www-form-urlencoded" },
      body: invBody.toString(),
    });
    const inv = await invRes.json() as { id: string; status: string };
    const sendRes = await fetch(`https://api.stripe.com/v1/invoices/${inv.id}/send`, {
      method: "POST",
      headers: { authorization: `Bearer ${bearer}` },
    });
    const sent = await sendRes.json() as { id: string; status: string; hosted_invoice_url?: string };
    return NextResponse.json({
      invoice_id: sent.id,
      status: sent.status,
      hosted_invoice_url: sent.hosted_invoice_url ?? null,
    });
